import{_ as s,o as i,c as a,ae as t}from"./chunks/framework.BMBGeRFM.js";const k=JSON.parse('{"title":"Under The Hood","description":"","frontmatter":{},"headers":[],"relativePath":"styles/advanced/index.md","filePath":"styles/advanced/index.md"}'),o={name:"styles/advanced/index.md"};function n(l,e,r,d,h,c){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="under-the-hood" tabindex="-1">Under The Hood <a class="header-anchor" href="#under-the-hood" aria-label="Permalink to &quot;Under The Hood&quot;">​</a></h1><p>So you&#39;ve got style files working and you&#39;re curious what&#39;s actually happening when you call <code>farben_build::run()</code>. Let&#39;s pull back the curtain.</p><h2 id="the-full-pipeline" tabindex="-1">The Full Pipeline <a class="header-anchor" href="#the-full-pipeline" aria-label="Permalink to &quot;The Full Pipeline&quot;">​</a></h2><p>When <code>build.rs</code> runs, <code>farben-build</code> reads your <code>.frb.toml</code> file and generates <strong>two separate output files</strong> in Cargo&#39;s <code>OUT_DIR </code>. They have different consumers and different jobs, which is why there are two of them.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.frb.toml  →  farben-build  →  farben_styles.rs       (runtime)</span></span>
<span class="line"><span>                            →  farben_registry.lsv    (compile-time)</span></span></code></pre></div><p>Let&#39;s go through each one.</p><h2 id="farben-styles-rs-the-runtime-file" tabindex="-1"><code>farben_styles.rs</code>: The Runtime File <a class="header-anchor" href="#farben-styles-rs-the-runtime-file" aria-label="Permalink to &quot;\`farben_styles.rs\`: The Runtime File&quot;">​</a></h2><p>This is a Rust source file. Your <code>load_styles!()</code> call expands to a single <code>include!()</code>:</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// what load_styles!() actually is</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">include!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">concat!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">env!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;OUT_DIR&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/farben_styles.rs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span></code></pre></div><p>That <code>include!()</code> pastes the generated file directly at the call site. It&#39;s not an import. The file it pastes in looks roughly like this:</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pub</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> init_styles</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    farben</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">insert_style</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">farben</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Style</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">parse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[bold red]&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">unwrap_or_else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> panic!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;{e}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)));</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    farben</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">set_prefix</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;error:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">unwrap_or_else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> panic!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;{e}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">));</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>This is where <code>init_styles()</code> comes from. When you call it at the top of <code>main()</code>, these <code>insert_style</code> and <code>set_prefix</code> calls run and register everything into the global registry.</p><p>::: note Notice the brackets around <code>bold red</code> in the generated code. Your config has <code>error = &quot;bold red&quot;</code> (no brackets), but <code>farben-build</code> wraps the value automatically before writing it out. You don&#39;t have to think about it. :::</p><h2 id="farben-registry-lsv-the-compile-time-file" tabindex="-1"><code>farben_registry.lsv</code>: The Compile-Time File <a class="header-anchor" href="#farben-registry-lsv-the-compile-time-file" aria-label="Permalink to &quot;\`farben_registry.lsv\`: The Compile-Time File&quot;">​</a></h2><p>LSV stands for &quot;line separated values.&quot; It&#39;s a custom format invented specifically to avoid any parser headache or dependencies. The whole point is that <code>farben-build</code> has <strong>zero runtime dependencies</strong>, so it rolls its own minimal format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>error=bold red</span></span>
<span class="line"><span>my:error=bold underline red</span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>error=error:</span></span>
<span class="line"><span>my:error=[ERROR]</span></span></code></pre></div><p>Styles come first, then a <code>---</code> separator, and then prefixes. Keys use <code>=</code> with no spaces around it. That&#39;s the entire spec, made specifically so I don&#39;t write any complicated stuff. Oh, and if it isn&#39;t obvious enough, don&#39;t edit the files unless you know what you&#39;re doing.</p><p>This file is read by the <code>farben-macros</code> proc macros: <code>color!()</code>, <code>colorb!()</code>, and <code>validate_color!()</code>. Every time one of those macros runs, it calls <code>load_registry()</code> first, which:</p><ol><li>Reads <code>farben_registry.lsv</code> from <code>OUT_DIR</code></li><li>Splits on <code>---\\n</code> to separate styles from prefixes</li><li>Calls <code>farben_core::registry::insert_style</code> for each style line</li><li>Calls <code>farben_core::registry::set_prefix</code> for each prefix line</li><li>Returns silently if the file doesn&#39;t exist</li></ol><p>It returns silently because no build script means no <code>.lsv</code> file, and the macros just continue without custom styles.</p><p>This is how <code>color!(&quot;[error]text&quot;)</code> resolves <code>[error]</code> at compile time. The proc macro runs inside the Cargo build process, which already executed <code>build.rs</code> and wrote the registry to <code>OUT_DIR</code> before any macro invocations happen.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The <code>load_registry()</code> call happens inside the proc macro crate, not in your code. You never call it directly. It&#39;s the invisible setup step before every <code>color!()</code> expansion.</p></div><h2 id="why-two-files" tabindex="-1">Why Two Files? <a class="header-anchor" href="#why-two-files" aria-label="Permalink to &quot;Why Two Files?&quot;">​</a></h2><p>Fair question. Why not just use <code>farben_registry.lsv</code> for both purposes?</p><p>The runtime side needs actual Rust function calls at program startup. You can&#39;t execute a data file. The <code>include!()</code> approach generates those calls as real Rust code, which is why <code>farben_styles.rs</code> exists at all.</p><p>The compile-time side has the opposite problem. Proc macros run inside the Cargo build process and have access to <code>OUT_DIR</code>. But they can&#39;t call <code>init_styles()</code> because that function lives in your code, not in the macro crate. They can read a file from disk though, which is exactly what the <code>.lsv</code> format enables.</p><p>So: one file for each phase of the build.</p><details class="details custom-block"><summary>Why not generate a third artifact the macros can <code>include!()</code> too?</summary><p>Proc macros run in a sandboxed environment and can&#39;t use <code>include!()</code> from <code>OUT_DIR</code> the same way user code can. Reading a file directly with <code>std::fs::read_to_string</code> is simpler and more reliable inside a proc macro context.</p></details><h2 id="the-frb-toml-parser" tabindex="-1">The <code>.frb.toml</code> Parser <a class="header-anchor" href="#the-frb-toml-parser" aria-label="Permalink to &quot;The \`.frb.toml\` Parser&quot;">​</a></h2><p>Despite the <code>.toml</code> extension, this file is <strong>not parsed by the <code>toml</code> crate</strong>. <code>farben-build</code> has zero dependencies and implements its own parser from scratch. It handles:</p><ul><li><code>[styles]</code> and <code>[prefixes]</code> section headers</li><li><code>[styles.namespace]</code> and <code>[prefixes.namespace]</code> for namespaced keys like <code>[my:error]</code></li><li><code>key = &quot;value&quot;</code> pairs where values must be double-quoted</li><li><code>#</code> line comments</li><li>Blank lines (ignored)</li></ul><p>Only two top-level sections are valid: <code>styles</code> and <code>prefixes</code>. Any other section name is a build error. Anything that doesn&#39;t match these rules produces a build error too.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If your build fails with a parse error from <code>farben-build</code>, it&#39;s almost always a missing quote around a value or a typo in a section name. Check those first.</p></div><p>The setup steps for creating your <code>.frb.toml</code> and wiring up <code>build.rs</code> are all covered on the <a href="/farben/styles/styles-toml/">Theme Files</a> page if you need them.</p>`,34)])])}const u=s(o,[["render",n]]);export{k as __pageData,u as default};
